  },

  async extractObservations() {
    const engine = new IntegrationEngine();
    return await engine.extractJournalObservations();
  },

  async planSession() {
    const engine = new IntegrationEngine();
    return await engine.generateSessionPlan();
  },
};

export default integrationPlugin;

